queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:functionId ?cg . ?child a :Functions ; p:functionId ?cg . ?l p:hrProfessionalId ?pg . ?parent a :Hr_Professionals ; p:id ?pg . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hr_Professionals } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?description WHERE {
  ?hr_professionals_functions a :Hr_Professionals_Functions .
  ?functions a :Functions .
  ?hr_professionals_functions p:hasFunctions ?functions .
  ?hr_professionals a :Hr_Professionals .
  ?hr_professionals_functions p:hasHr_Professionals ?hr_professionals .
  ?hr_professionals p:name ?name .
  ?functions p:description ?description .
} }
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:functionId ?cg . ?child a :Functions ; p:functionId ?cg . ?l p:hrProfessionalId ?pg . ?parent a :Hr_Professionals ; p:id ?pg . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hr_Professionals } }
  FILTER(?nf = ?total)
} }
}
